import{_ as o,o as t,c as r,a3 as a}from"./chunks/framework.oxq6d-og.js";const p=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"en/troubleshooting.md","filePath":"en/troubleshooting.md"}'),s={name:"en/troubleshooting.md"};function d(n,e,c,i,l,h){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><p>Treat an error together with the stage where it occurred. NThread, accessors, and hooks operate on the same target process, so one timeout symptom can have different causes.</p><p>For <code>NoSleepAddressError</code>, <code>NoPushretAddressError</code>, or <code>NoJumpAddressError</code>, verify Windows x64, <code>ntdll</code>/<code>kernel32</code>/<code>kernelbase</code>, and completed async initialization. For <code>CallTimeoutError</code>, inspect the address, signature, thread state, and suspend ownership before increasing the timeout. For <code>CallThreadDiedError</code>, use a fresh target and isolate the call with a small returning function.</p><p>If <code>expectedRsp</code> is set, both <code>call()</code> and <code>callSync()</code> warn on a return-stack mismatch. Record PID, driving thread ID, target address, first bytes, argument types, <code>RIP</code>, <code>RSP</code>, argument registers, result register, timeout result, and thread exit state in hexadecimal-safe form.</p>',4)])])}const m=o(s,[["render",d]]);export{p as __pageData,m as default};
